import {
	addMeltEventListener,
	makeElement,
	createElHelpers,
	disabledAttr,
	omit,
	overridable,
	styleToString,
	toWritableStores,
} from '$lib/internal/helpers/index.js';
import type { MeltActionReturn } from '$lib/internal/types.js';
import { derived, writable } from 'svelte/store';
import type { CollapsibleEvents } from './events.js';
import type { CreateCollapsibleProps } from './types.js';

const defaults = {
	defaultOpen: false,
	disabled: false,
	forceVisible: false,
} satisfies CreateCollapsibleProps;

const { name } = createElHelpers('collapsible');

export function createCollapsible(props?: CreateCollapsibleProps) {
	const withDefaults = { ...defaults, ...props } satisfies CreateCollapsibleProps;

	const options = toWritableStores(omit(withDefaults, 'open', 'defaultOpen', 'onOpenChange'));
	const { disabled, forceVisible } = options;

	const openWritable = withDefaults.open ?? writable(withDefaults.defaultOpen);
	const open = overridable(openWritable, withDefaults?.onOpenChange);

	const root = makeElement(name(), {
		stores: [open, disabled],
		returned: ([$open, $disabled]) =>
			({
				'data-state': $open ? 'open' : 'closed',
				'data-disabled': disabledAttr($disabled),
			} as const),
	});

	const trigger = makeElement(name('trigger'), {
		stores: [open, disabled],
		returned: ([$open, $disabled]) =>
			({
				'data-state': $open ? 'open' : 'closed',
				'data-disabled': disabledAttr($disabled),
				disabled: disabledAttr($disabled),
			} as const),
		action: (node: HTMLElement): MeltActionReturn<CollapsibleEvents['trigger']> => {
			const unsub = addMeltEventListener(node, 'click', () => {
				const disabled = node.dataset.disabled !== undefined;
				if (disabled) return;
				open.update(($open) => !$open);
			});

			return {
				destroy: unsub,
			};
		},
	});

	const isVisible = derived(
		[open, forceVisible],
		([$open, $forceVisible]) => $open || $forceVisible
	);

	const content = makeElement(name('content'), {
		stores: [isVisible, open, disabled],
		returned: ([$isVisible, $open, $disabled]) =>
			({
				'data-state': $open ? 'open' : 'closed',
				'data-disabled': disabledAttr($disabled),
				hidden: $isVisible ? undefined : true,
				style: $isVisible ? undefined : styleToString({ display: 'none' }),
			} as const),
	});

	return {
		elements: {
			root,
			trigger,
			content,
		},
		states: {
			open,
		},
		options,
	};
}

import {
	makeElement,
	effect,
	isBrowser,
	omit,
	overridable,
	styleToString,
	toWritableStores,
} from '$lib/internal/helpers/index.js';
import { writable } from 'svelte/store';
import type { CreateAvatarProps } from './types.js';

const defaults = {
	src: '',
	delayMs: 0,
	onLoadingStatusChange: undefined,
} satisfies CreateAvatarProps;

export const createAvatar = (props?: CreateAvatarProps) => {
	const withDefaults = { ...defaults, ...props } satisfies CreateAvatarProps;

	const options = toWritableStores(omit(withDefaults, 'loadingStatus', 'onLoadingStatusChange'));
	const { src, delayMs } = options;

	const loadingStatusWritable = withDefaults.loadingStatus ?? writable('loading');
	const loadingStatus = overridable(loadingStatusWritable, withDefaults?.onLoadingStatusChange);

	effect([src, delayMs], ([$src, $delayMs]) => {
		if (isBrowser) {
			const image = new Image();
			image.src = $src;
			image.onload = () => {
				if (delayMs !== undefined) {
					const timerId = window.setTimeout(() => {
						loadingStatus.set('loaded');
					}, $delayMs);
					return () => window.clearTimeout(timerId);
				} else {
					loadingStatus.set('loaded');
				}
			};
			image.onerror = () => {
				loadingStatus.set('error');
			};
		}
	});

	const image = makeElement('avatar-image', {
		stores: [src, loadingStatus],
		returned: ([$src, $loadingStatus]) => {
			const imageStyles = styleToString({
				display: $loadingStatus === 'loaded' ? 'block' : 'none',
			});
			return {
				src: $src,
				style: imageStyles,
			} as const;
		},
	});

	const fallback = makeElement('avatar-fallback', {
		stores: [loadingStatus],
		returned: ([$loadingStatus]) => {
			return {
				style:
					$loadingStatus === 'loaded'
						? styleToString({
								display: 'none',
						  })
						: undefined,
				hidden: $loadingStatus === 'loaded' ? true : undefined,
			} as const;
		},
	});

	return {
		elements: {
			image,
			fallback,
		},
		states: {
			loadingStatus,
		},
		options,
	};
};

const filteredItems = $derived.by(() => {
  const searchLower = search.trim().toLowerCase();
  if (searchLower === "") return items;

  const check = (x?: string) => x?.toLowerCase().includes(searchLower);
  return items.filter((item) => check(item.label) || check(item.description) || item.keywords?.some(check));
});

$effect(() => {
  if (filteredItems.length > 0 && selectedIndex >= filteredItems.length) {
    selectedIndex = Math.max(filteredItems.length - 1, 0);
  }
});

function handleKeydown(e: KeyboardEvent) {
  if (!open) return;

  if (handleGlobalKeydown(e)) return;

  switch (e.key) {
    case "j":
      if (!vim || e.ctrlKey) break;
    // falls through
    case "ArrowDown":
      e.preventDefault();
      selectedIndex = Math.max(Math.min(selectedIndex + 1, filteredItems.length - 1), 0);
      scrollToSelected();
      break;
    case "k":
      if (!vim || e.ctrlKey) break;
    // falls through
    case "ArrowUp":
      e.preventDefault();
      selectedIndex = Math.max(selectedIndex - 1, 0);
      scrollToSelected();
      break;
    case "Enter":
      e.preventDefault();
      if (filteredItems[selectedIndex]) {
        selectItem(filteredItems[selectedIndex]);
      }
      break;
  }
}

function scrollToSelected() {
  if (!containerElement) return;

  const listElement = containerElement.querySelector("ul");
  if (!listElement) return;

  const selectedElement = listElement.querySelector(`#${CSS.escape(filteredItems[selectedIndex]?.id)}`) as HTMLElement;
  if (!selectedElement) return;

  const listRect = listElement.getBoundingClientRect();
  const elementRect = selectedElement.getBoundingClientRect();

  if (elementRect.bottom > listRect.bottom) {
    selectedElement.scrollIntoView({ block: "end", behavior: "auto" });
  } else if (elementRect.top < listRect.top) {
    selectedElement.scrollIntoView({ block: "start", behavior: "auto" });
  }
}

function selectItem(item: CommandItem) {
  item.onselect();
  open = false;
  search = "";
  selectedIndex = 0;
}

const handleGlobalKeydown = (e: KeyboardEvent) => {
  if ((e.metaKey || e.ctrlKey) && e.key === shortcutKey) {
    e.preventDefault();
    open = !open;
    selectedIndex = 0;
    return true;
  }
};

function init(dlg: HTMLDialogElement) {
  containerElement = dlg;
}

export class PresenceManager {
	#opts: PresenceManagerOpts;
	#enabled: boolean;
	#afterAnimations: AnimationsComplete;
	#shouldRender = $state(false);
	#transitionStatus = $state<TransitionState>(undefined);
	#hasMounted = false;
	#transitionFrame: number | null = null;

	constructor(opts: PresenceManagerOpts) {
		this.#opts = opts;
		this.#shouldRender = opts.open.current;
		this.#enabled = opts.enabled ?? true;
		this.#afterAnimations = new AnimationsComplete({
			ref: this.#opts.ref,
			afterTick: this.#opts.open,
		});
		onDestroyEffect(() => this.#clearTransitionFrame());

		watch(
			() => this.#opts.open.current,
			(isOpen) => {
				if (!this.#hasMounted) {
					this.#hasMounted = true;
					return;
				}

				this.#clearTransitionFrame();

				if (!isOpen && this.#opts.shouldSkipExitAnimation?.()) {
					this.#shouldRender = false;
					this.#transitionStatus = undefined;
					this.#opts.onComplete?.();
					return;
				}

				if (isOpen) this.#shouldRender = true;
				this.#transitionStatus = isOpen ? "starting" : "ending";
				if (isOpen) {
					this.#transitionFrame = window.requestAnimationFrame(() => {
						this.#transitionFrame = null;
						if (this.#opts.open.current) {
							this.#transitionStatus = undefined;
						}
					});
				}

				if (!this.#enabled) {
					if (!isOpen) {
						this.#shouldRender = false;
					}
					this.#transitionStatus = undefined;
					this.#opts.onComplete?.();
					return;
				}

				this.#afterAnimations.run(() => {
					if (isOpen === this.#opts.open.current) {
						if (!this.#opts.open.current) {
							this.#shouldRender = false;
						}
						this.#transitionStatus = undefined;
						this.#opts.onComplete?.();
					}
				});
			}
		);
	}

	get shouldRender() {
		return this.#shouldRender;
	}

	get transitionStatus(): TransitionState {
		return this.#transitionStatus;
	}

	#clearTransitionFrame(): void {
		if (this.#transitionFrame === null) return;
		window.cancelAnimationFrame(this.#transitionFrame);
		this.#transitionFrame = null;
	}
}
